external_knowledge:
- "Windy City" is a nickname for Chicago;
- "shining stars" metaphorically refers to players with high performance;
- "keeping their feet on the ground" implies they are actively playing in the league;
- "soar higher than their peers" means they have above-average performance in terms of points per game;
- "brightest to the slightly less radiant" refers to ordering by points per game in descending order.

sql:
SELECT AVG(height) AS average_height
FROM players
WHERE draft_year > 2000;

SELECT game_id, AVG(points_scored) AS avg_points_per_game
FROM game_logs
GROUP BY game_id;

SELECT p.player_name, ps.total_points
FROM players p
INNER JOIN player_statistics ps ON p.player_id = ps.player_id
WHERE ps.season_id = (
    SELECT MAX(season_id) FROM player_statistics
)
AND ps.total_points = (
    SELECT MAX(total_points)
    FROM player_statistics
    WHERE season_id = (
        SELECT MAX(season_id) FROM player_statistics
    )
);

SELECT player_id, game_id, AVG(points_scored) AS average_points_scored
FROM game_logs
GROUP BY player_id, game_id;

SELECT SUM(points_scored) AS total_points
FROM game_logs
WHERE player_id = 0 AND season_id = 1;

SELECT COUNT(*)
FROM players
WHERE player_id IN (
  SELECT captain_id
  FROM teams
);
